CODE_EXAMPLE:
public interface IButton {
  string Render();
}

public interface ITextbox {
  string Render();
}

public interface IUiFactory {
  IButton CreateButton();
  ITextbox CreateTextbox();
}

public class WindowsButton : IButton {
  public string Render() => "windows-button";
}

public class WindowsTextbox : ITextbox {
  public string Render() => "windows-textbox";
}

public class WindowsUiFactory : IUiFactory {
  public IButton CreateButton() => new WindowsButton();
  public ITextbox CreateTextbox() => new WindowsTextbox();
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Factory_CreatesMatchingWindowsComponents() {
  IUiFactory factory = new WindowsUiFactory();
  var button = factory.CreateButton();
  var textbox = factory.CreateTextbox();

  Assert.AreEqual("windows-button", button.Render());
  Assert.AreEqual("windows-textbox", textbox.Render());
}

[TestMethod]
public void Factory_ReturnsInterfaceTypes() {
  IUiFactory factory = new WindowsUiFactory();
  Assert.IsNotNull(factory.CreateButton());
  Assert.IsNotNull(factory.CreateTextbox());
}
